const ACTIVE_WORKING_DOCUMENTS_STORAGE_KEY = 'yiyu.workspace.activeWorkingDocuments.v1';
const ACTIVE_WORKING_DOCUMENTS_MAX_AGE_MS = 6 * 60 * 60 * 1000;
const ACTIVE_WORKING_DOCUMENTS_LIMIT = 6;

type RecentUsedDocument = {
  documentId: string;
  title: string;
  path: string;
  usedAt: number;
};

const RECENT_USED_DOCUMENTS_STORAGE_KEY = 'yiyu.workspace.recentUsedDocuments.v1';
const RECENT_USED_DOCUMENTS_LIMIT = 30;

function readStoredRecentUsedDocuments(clientId: string): RecentUsedDocument[] {
  if (!clientId || typeof window === 'undefined') return [];
  try {
    const raw = window.localStorage.getItem(RECENT_USED_DOCUMENTS_STORAGE_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw) as Record<string, RecentUsedDocument[]>;
    const list = Array.isArray(parsed?.[clientId]) ? parsed[clientId] : [];
    return list
      .filter((item) =>
        item
        && typeof item.documentId === 'string'
        && typeof item.title === 'string'
        && typeof item.path === 'string'
        && typeof item.usedAt === 'number',
      )
      .slice(0, RECENT_USED_DOCUMENTS_LIMIT);
  } catch {
    return [];
  }
}

function writeStoredRecentUsedDocuments(clientId: string, docs: RecentUsedDocument[]) {
  if (!clientId || typeof window === 'undefined') return;
  try {
    const raw = window.localStorage.getItem(RECENT_USED_DOCUMENTS_STORAGE_KEY);
    const parsed = raw ? (JSON.parse(raw) as Record<string, RecentUsedDocument[]>) : {};
    parsed[clientId] = docs.slice(0, RECENT_USED_DOCUMENTS_LIMIT);
    window.localStorage.setItem(RECENT_USED_DOCUMENTS_STORAGE_KEY, JSON.stringify(parsed));
  } catch {
    // ignore
  }
}

function normalizeWorkingDocumentStatus(value?: string | null): ActiveWorkingDocument['status'] {
  if (value === 'ready' || value === 'partial_ready' || value === 'failed') return value;
  if (value === 'queued') return 'queued';
  return 'processing';
}

const TECHNICAL_FAILURE_MARKERS: readonly string[] = [
  'validation error for',
  'Traceback',
  'errors.pydantic.dev',
  'Input should be',
  'pydantic_core',
  "<class '",
];

const KNOWN_FAILURE_TAGS: Record<string, string> = {
  internal_error: '回答过程出现了系统错误，请重试一次。',
  user_canceled: '已取消生成。',
  chat_executor_unavailable: '后台执行器暂不可用，请稍后重试。',
  ai_result_unavailable: 'AI 暂时无法生成回答，请稍后重试。',
  llm_local_fallback_after_retry: '在线模型不可用，已自动退回本地兜底回答。',
  llm_partial_preserved_after_stale_recovery: '上次回答中断，已保留部分内容，请重试以获取完整回答。',
  no_relevant_materials: '当前客户资料中没有命中相关内容。',
};

function friendlyFailureMessage(raw: string | null | undefined, fallback = '请稍后重试。'): string {
  const text = (raw || '').trim();
  if (!text) return fallback;
  if (KNOWN_FAILURE_TAGS[text]) return KNOWN_FAILURE_TAGS[text];
  if (TECHNICAL_FAILURE_MARKERS.some((marker) => text.includes(marker))) {
    return KNOWN_FAILURE_TAGS.internal_error;
  }
  if (text.length > 200 || text.includes('\n')) {
    return KNOWN_FAILURE_TAGS.internal_error;
  }
  return text;
}

function mergeActiveWorkingDocuments(
  incoming: ActiveWorkingDocument[],
  existing: ActiveWorkingDocument[],
) {
  const seen = new Set<string>();
  const merged: ActiveWorkingDocument[] = [];
  for (const item of [...incoming, ...existing]) {
    const documentId = String(item.documentId || '').trim();
    if (!documentId || seen.has(documentId)) continue;
    seen.add(documentId);
    merged.push({ ...item, documentId });
    if (merged.length >= ACTIVE_WORKING_DOCUMENTS_LIMIT) break;
  }
  return merged;
}

function buildActiveWorkingDocumentsFromImports(importResults: ImportRecord[]) {
  const timestamp = Date.now();
  const docs: ActiveWorkingDocument[] = [];
  for (const result of importResults) {
    for (const document of result.documents || []) {
      const documentId = String(document.documentId || '').trim();
      if (!documentId) continue;
      docs.push({
        documentId,
        title: document.title || document.fileName || '资料',
        fileName: document.fileName || document.title || '资料',
        path: document.path || '',
        importId: result.id,
        jobId: result.jobId || null,
        status: normalizeWorkingDocumentStatus(result.status === 'failed' ? 'failed' : result.status),
        preview: null,
        lastError: null,
        updatedAt: timestamp,
      });
    }
  }
  return docs;
}

function readStoredActiveWorkingDocuments(clientId: string) {
  if (typeof window === 'undefined' || !clientId) return [];
  try {
    const raw = window.sessionStorage.getItem(ACTIVE_WORKING_DOCUMENTS_STORAGE_KEY);
    const parsed = raw ? JSON.parse(raw) : {};
    const stored = Array.isArray(parsed?.[clientId]) ? parsed[clientId] : [];
    const now = Date.now();
    return stored
      .filter((item: Partial<ActiveWorkingDocument>) =>
        item?.documentId
        && typeof item.updatedAt === 'number'
        && now - item.updatedAt <= ACTIVE_WORKING_DOCUMENTS_MAX_AGE_MS,
      )
      .slice(0, ACTIVE_WORKING_DOCUMENTS_LIMIT) as ActiveWorkingDocument[];
  } catch {
    return [];
  }
}

function writeStoredActiveWorkingDocuments(clientId: string, docs: ActiveWorkingDocument[]) {
  if (typeof window === 'undefined' || !clientId) return;
  try {
    const raw = window.sessionStorage.getItem(ACTIVE_WORKING_DOCUMENTS_STORAGE_KEY);
    const parsed = raw ? JSON.parse(raw) : {};
    const next = {
      ...(parsed && typeof parsed === 'object' ? parsed : {}),
      [clientId]: docs.slice(0, ACTIVE_WORKING_DOCUMENTS_LIMIT),
    };
    window.sessionStorage.setItem(ACTIVE_WORKING_DOCUMENTS_STORAGE_KEY, JSON.stringify(next));
  } catch {
    // Session recovery is best-effort; chat still works without it.
  }
}

