const buildNameBadge = (name: string) => {
  const trimmed = name.trim();
  if (!trimmed) return '未';
  const firstChar = trimmed[0];
  if (COMMON_SURNAME_SET.has(firstChar) && trimmed.length > 1) {
    return trimmed[1];
  }
  return firstChar;
};

