                          <span className="shrink-0 text-[10px] font-bold tabular-nums text-[#5B7BFE]">
                            {knowledgeJobProgressView.total > 0 ? `${knowledgeJobProgressView.percent}%` : knowledgeJobProgressView.statusLabel}
                          </span>
